package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.net.URL;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    private URL mockUrl;
    private InputStream mockInputStream;
    private Charset charset;
    private CSVFormat format;

    @BeforeEach
    void setUp() throws IOException {
        mockUrl = mock(URL.class);
        mockInputStream = mock(InputStream.class);
        when(mockUrl.openStream()).thenReturn(mockInputStream);
        charset = Charset.forName("UTF-8");
        format = mock(CSVFormat.class);
    }

    @Test
    void testParse_withValidParameters_returnsCSVParser() throws IOException {
        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            // Assertions.notNull should be called 3 times, we verify that it doesn't throw
            mockedAssertions.when(() -> Assertions.notNull(any(), any())).then(invocation -> null);

            CSVParser parser = CSVParser.parse(mockUrl, charset, format);

            assertNotNull(parser);
            // We cannot verify internals easily, but parser should not be closed immediately
            assertFalse(parser.isClosed());
        }
        verify(mockUrl, times(1)).openStream();
    }

    @Test
    void testParse_withNullUrl_throwsException() {
        assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(null, charset, format);
        });
    }

    @Test
    void testParse_withNullCharset_throwsException() {
        assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(mockUrl, null, format);
        });
    }

    @Test
    void testParse_withNullFormat_throwsException() {
        assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(mockUrl, charset, null);
        });
    }
}
